CREATE TRIGGER tr_flight_preparation
ON dbo.Flight_preparation
FOR INSERT, UPDATE, DELETE
AS 
BEGIN
    SET NOCOUNT ON;

    DECLARE @current_date DATETIME;
    SET @current_date = GETDATE();

    DECLARE @preparation_id INT;
    DECLARE @aircraft_id INT;
    DECLARE @completed_work NVARCHAR(MAX);

    IF EXISTS (SELECT * FROM inserted)
    BEGIN
        SELECT @preparation_id = preparation_id,
               @aircraft_id = aircraft_id,
               @completed_work = completed_work 
        FROM inserted;

        INSERT INTO dbo.Flight_preparation_history
        (preparation_date, aircraft_id, completed_work, performed_by, event_type, event_date)
        VALUES
        (@current_date, @aircraft_id, @completed_work, USER_NAME(), 'insert', @current_date);
    END

    IF EXISTS (SELECT * FROM deleted)
    BEGIN
        SELECT @preparation_id = preparation_id,
               @aircraft_id = aircraft_id,
               @completed_work = completed_work 
        FROM deleted;

        INSERT INTO dbo.Flight_preparation_history
        (preparation_date, aircraft_id, completed_work, performed_by, event_type, event_date)
        VALUES
        (@current_date, @aircraft_id, @completed_work, USER_NAME(), 'delete', @current_date);
    END

    IF EXISTS (SELECT * FROM inserted i JOIN deleted d ON i.preparation_id = d.preparation_id)
    BEGIN
        SELECT @preparation_id = i.preparation_id,
               @aircraft_id = i.aircraft_id,
               @completed_work = i.completed_work 
        FROM inserted i JOIN deleted d ON i.preparation_id = d.preparation_id;

        INSERT INTO dbo.Flight_preparation_history
        (preparation_date, aircraft_id, completed_work, performed_by, event_type, event_date)
        VALUES
        (@current_date, @aircraft_id, @completed_work, USER_NAME(), 'update', @current_date);
    END
END; 

CREATE TABLE dbo.Flight_preparation_history
(
    event_id INT IDENTITY PRIMARY KEY,
    preparation_date DATETIME,
    aircraft_id INT,
    completed_work NVARCHAR(MAX),
    performed_by NVARCHAR(100),
    event_type NVARCHAR(10),
    event_date DATETIME
);

